module top_module(
  input reset,
  input clk,
  output rst_sync
);parameter n = 2; // number of cycles that reset must be stable

reg [1:0] sync_reset; // two-stage synchronizer

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
  sync_reset[0] <= reset;
  sync_reset[1] <= sync_reset[0];
end

assign rst_sync = sync_reset[1];

endmodule
